    color: #888 !important; 
    transition: all 0.2s ease;
}
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt:not(.completion_prompt_manager_prompt_disabled):hover .prompt_manager_prompt_controls span {
    color: var(--primary-pink) !important; 
}
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt.completion_prompt_manager_prompt_disabled .prompt_manager_prompt_controls span {
    color: #555 !important;
}

input[type="checkbox"] {
    appearance: none;
    -webkit-appearance: none;
    position: relative;
    cursor: pointer;
    vertical-align: middle;
    margin-right: 8px;
    width: 1.25em;
    height: 1.25em;
    background: var(--dark-bg);
    border-radius: 8px;
    border: none;
    box-shadow: 
        2px 2px 5px #111113,
        -2px -2px 5px #232327;
    transition: all 0.2s ease-in-out;
}
input[type="checkbox"]:checked::after {
    content: '✔';
    color: var(--primary-pink); 
    font-size: 0.9em;
    font-weight: 900;
    position: absolute;
    top: 51%;
    left: 50%;
    transform: translate(-50%, -50%);
    line-height: 1;
}
input[type="checkbox"]:hover {
    transform: translateY(-1px);
    box-shadow: 
        3px 3px 6px #0f0f11,
        -3px -3px 6px #252529;
}
input[type="checkbox"]:active {
    transform: translateY(0px);
    box-shadow: 
        inset 2px 2px 4px #111113,
        inset -2px -2px 4px #232327;
}
input[type="radio"] {
    appearance: none;
    -webkit-appearance: none;
    position: relative;
    cursor: pointer;
    vertical-align: middle;
    margin-right: 8px;
    width: 1.25em;
    height: 1.25em;
    background: var(--dark-bg);
    border-radius: 50%;
    border: none;
    box-shadow: 
        2px 2px 5px #111113,
        -2px -2px 5px #232327;
    transition: all 0.2s ease-in-out;
}
input[type="radio"]:checked::after {
    content: '';
    width: 0.6em;
    height: 0.6em;
    border-radius: 50%;
    background-color: var(--primary-pink); 
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
}
input[type="radio"]:hover {
    transform: translateY(-1px);
    box-shadow: 
        3px 3px 6px #0f0f11,
        -3px -3px 6px #252529;
}
input[type="radio"]:active {
    transform: translateY(0px);
    box-shadow: 
        inset 2px 2px 4px #111113,
        inset -2px -2px 4px #232327;
}
input[type="range"] {
    -webkit-appearance: none;
    appearance: none;
    width: 100%;
    background: transparent;
    cursor: pointer;
    outline: none;
    padding: 0;
    box-shadow: none !important;
    filter: none !important;
}
input[type="range"]::-webkit-slider-runnable-track {
    width: 100%;
    height: 8px;
    background: var(--dark-bg);
    border-radius: 9999px;
    box-shadow: 
        inset 2px 2px 4px #111113,
        inset -2px -2px 4px #232327;
}
input[type="range"]::-moz-range-track {
    width: 100%;
    height: 8px;
    background: var(--dark-bg);
    border-radius: 9999px;
    box-shadow: 
        inset 2px 2px 4px #111113,
        inset -2px -2px 4px #232327;
}
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    height: 1.5em;
    width: 1.5em;
    border-radius: 50%;
    background: var(--accent-pink); 
    border: none;
    margin-top: -0.4em;
    box-shadow: 
        2px 2px 5px rgba(0, 0, 0, 0.4),
        -2px -2px 5px rgba(255, 133, 161, 0.2);
    transition: transform 0.2s ease-out;
}
input[type="range"]::-moz-range-thumb {
    height: 1.5em;
    width: 1.5em;
    border-radius: 50%;
    background: var(--accent-pink);
    border: none;
    box-shadow: 
        2px 2px 5px rgba(0, 0, 0, 0.4),
        -2px -2px 5px rgba(255, 133, 161, 0.2);
    transition: transform 0.2s ease-out;
}
.menu_button {
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
    border-radius: 12px !important;
    padding: 8px 12px;
    margin: 2px;
    font-size: 0.9em !important;
    font-weight: 600 !important;
    color: #888 !important; 
    cursor: pointer;
    transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    line-height: 1;
}
.menu_button:hover {
    transform: translateY(-2px) scale(1.05);
    color: var(--primary-pink) !important; 
    background-color: rgba(255, 133, 161, 0.1) !important;
}
.menu_button:active {
    transform: translateY(0px) scale(0.98);
    background-color: rgba(255, 133, 161, 0.2) !important;
    transition-duration: 0.1s;
}
.menu_button.menu_button_icon {
    border-radius: 50% !important;
    padding: 10px;
    width: auto;
    height: auto;
}
.menu_button.redWarningBG,
.menu_button.red_button {
    color: #ff8a80 !important;
    background-color: transparent !important;
}
.menu_button.redWarningBG:hover,
.menu_button.red_button:hover {
    color: #ff5252 !important;
    background-color: rgba(255, 82, 82, 0.1) !important;
}
#chat .mes.selected {
  background-color: transparent !important;
}


